export interface GeneralData {
  employer: string;
  employee: string;
  payPeriod: string;
  contractType: string;
  ccnl: string;
  level: string;
}

export interface LineItemExplanation {
  whatIsIt: string;
  whyItExists: string;
  whoPays: string;
  impact: {
    gross: boolean;
    net: boolean;
    tfr: boolean;
  };
  notes: string;
}

export interface LineItem {
  name: string;
  category: string; // e.g., "Retribuzione base", "Imposte", etc.
  amount: string; // Keeping as string to preserve original formatting, or parse as number
  explanation: LineItemExplanation;
}

export interface Calculations {
  grossHourlyRate: string;
  netHourlyRateEstimated: string;
  totalDeductions: string;
  deductionPercentage: string;
}

export interface ConsistencyCheck {
  isConsistent: boolean;
  message: string;
  severity: 'info' | 'warning' | 'error';
}

export interface SimpleExplanation {
  summary: string;
  keyTakeaways: string[];
}

export interface AnalysisResult {
  generalData: GeneralData;
  lineItems: LineItem[];
  calculations: Calculations;
  consistencyChecks: ConsistencyCheck[];
  simpleExplanation: SimpleExplanation;
  finalSummary: {
    netTotal: string;
    grossTotal: string;
    topImpactItems: string[];
    improvementTips: string;
  };
}

export type AnalysisStatus = 'idle' | 'extracting' | 'analyzing' | 'success' | 'error';

import { Schema, Type } from "@google/genai";

export const APP_NAME = "Busta Paga Expert AI";

export const PAYSLIP_ANALYSIS_PROMPT = `
Agisci come Esperto Senior in Paghe e Contributi (Consulenza del lavoro, CCNL italiani).
Analizza il testo estratto da una busta paga digitale italiana.

Segui rigorosamente queste fasi:

Fase 1: Parsing Dati Generali (Datore, Dipendente, Periodo, Contratto, CCNL, Livello). Se incerto, scrivi "Non determinabile".
Fase 2: Riconoscimento Voci. Classifica ogni riga rilevante (Retribuzione base, Straordinari, Ferie, Ratei, Contributi, Imposte, TFR, ecc).
Fase 3: Spiegazione Voce per Voce. Per ogni voce, spiega cos'è, perché esiste, chi la paga e l'influenza su Lordo/Netto/TFR.
Fase 4: Calcoli Automatici. Paga oraria lorda/netta, totale trattenute.
Fase 5: Verifiche Coerenza. Controlla logica matematica e inquadramento.
Fase 6: Spiegazione Semplice. Sintesi non tecnica.

Output Finale: Restituisci SOLO un JSON strutturato secondo lo schema fornito.
`;

export const ANALYSIS_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    generalData: {
      type: Type.OBJECT,
      properties: {
        employer: { type: Type.STRING },
        employee: { type: Type.STRING },
        payPeriod: { type: Type.STRING },
        contractType: { type: Type.STRING },
        ccnl: { type: Type.STRING },
        level: { type: Type.STRING },
      },
      required: ["employer", "employee", "payPeriod", "contractType", "ccnl", "level"],
    },
    lineItems: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          category: { type: Type.STRING },
          amount: { type: Type.STRING },
          explanation: {
            type: Type.OBJECT,
            properties: {
              whatIsIt: { type: Type.STRING, description: "Cos'è questa voce" },
              whyItExists: { type: Type.STRING, description: "Perché esiste" },
              whoPays: { type: Type.STRING, description: "Chi la paga (Azienda/Dipendente/INPS)" },
              impact: {
                type: Type.OBJECT,
                properties: {
                  gross: { type: Type.BOOLEAN },
                  net: { type: Type.BOOLEAN },
                  tfr: { type: Type.BOOLEAN },
                },
                required: ["gross", "net", "tfr"],
              },
              notes: { type: Type.STRING, description: "Note utili per il lavoratore" },
            },
            required: ["whatIsIt", "whyItExists", "whoPays", "impact", "notes"],
          },
        },
        required: ["name", "category", "amount", "explanation"],
      },
    },
    calculations: {
      type: Type.OBJECT,
      properties: {
        grossHourlyRate: { type: Type.STRING },
        netHourlyRateEstimated: { type: Type.STRING },
        totalDeductions: { type: Type.STRING },
        deductionPercentage: { type: Type.STRING },
      },
      required: ["grossHourlyRate", "netHourlyRateEstimated", "totalDeductions", "deductionPercentage"],
    },
    consistencyChecks: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          isConsistent: { type: Type.BOOLEAN },
          message: { type: Type.STRING },
          severity: { type: Type.STRING, enum: ["info", "warning", "error"] },
        },
        required: ["isConsistent", "message", "severity"],
      },
    },
    simpleExplanation: {
      type: Type.OBJECT,
      properties: {
        summary: { type: Type.STRING },
        keyTakeaways: { type: Type.ARRAY, items: { type: Type.STRING } },
      },
      required: ["summary", "keyTakeaways"],
    },
    finalSummary: {
      type: Type.OBJECT,
      properties: {
        netTotal: { type: Type.STRING },
        grossTotal: { type: Type.STRING },
        topImpactItems: { type: Type.ARRAY, items: { type: Type.STRING } },
        improvementTips: { type: Type.STRING },
      },
      required: ["netTotal", "grossTotal", "topImpactItems", "improvementTips"],
    },
  },
  required: ["generalData", "lineItems", "calculations", "consistencyChecks", "simpleExplanation", "finalSummary"],
};

import * as pdfjsLib from 'pdfjs-dist';

// Define the worker source URL.
// We use unpkg to point to the correct version matching the installed pdfjs-dist.
// This is critical for environments without complex bundler configs for workers.
pdfjsLib.GlobalWorkerOptions.workerSrc = `https://unpkg.com/pdfjs-dist@${pdfjsLib.version}/build/pdf.worker.min.js`;

export const extractTextFromPdf = async (file: File): Promise<string> => {
  try {
    const arrayBuffer = await file.arrayBuffer();
    const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
    const pdfDocument = await loadingTask.promise;

    let fullText = '';
    const numPages = pdfDocument.numPages;

    for (let pageNum = 1; pageNum <= numPages; pageNum++) {
      const page = await pdfDocument.getPage(pageNum);
      const textContent = await page.getTextContent();

      // Extract text items and join them with spaces/newlines to approximate layout
      const pageText = textContent.items
        .map((item: any) => item.str)
        .join(' ');

      fullText += `--- Pagina ${pageNum} ---\n${pageText}\n\n`;
    }

    if (fullText.trim().length < 50) {
        throw new Error("Il PDF sembra vuoto o è un'immagine scansionata (OCR non supportato). Carica un PDF digitale.");
    }

    return fullText;
  } catch (error) {
    console.error("Errore estrazione PDF:", error);
    throw new Error("Impossibile leggere il PDF. Assicurati che sia un documento digitale valido.");
  }
};

import { GoogleGenAI } from "@google/genai";
import { ANALYSIS_SCHEMA, PAYSLIP_ANALYSIS_PROMPT } from "../constants";
import { AnalysisResult } from "../types";

export const analyzePayslipWithGemini = async (pdfText: string): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key mancante.");
  }

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: [
        {
            role: 'user',
            parts: [
                { text: PAYSLIP_ANALYSIS_PROMPT },
                { text: `Ecco il contenuto estratto dal PDF della busta paga:\n\n${pdfText}` }
            ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: ANALYSIS_SCHEMA,
        temperature: 0.2, // Low temperature for factual consistency
      },
    });

    const textResponse = response.text;
    if (!textResponse) {
        throw new Error("Risposta vuota da Gemini.");
    }

    const jsonResponse = JSON.parse(textResponse) as AnalysisResult;
    return jsonResponse;

  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw new Error("Errore durante l'analisi AI della busta paga.");
  }
};

