import React from 'react';
import { ConsistencyCheck } from '../types';
import { AlertTriangle, Info, CheckCircle } from 'lucide-react';

interface Props {
  checks: ConsistencyCheck[];
}

const ConsistencyChecks: React.FC<Props> = ({ checks }) => {
  if (!checks || checks.length === 0) return null;

  const hasIssues = checks.some(c => !c.isConsistent);

  if (!hasIssues) return null;

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 mb-6">
        <h2 className="text-lg font-bold text-slate-800 mb-4">Verifiche & Anomalie</h2>
        <div className="space-y-3">
            {checks.map((check, idx) => {
                if (check.isConsistent && check.severity === 'info') return null; // Skip "all good" redundant info

                return (
                    <div key={idx} className={`flex items-start gap-3 p-3 rounded-lg border ${
                        check.severity === 'error' ? 'bg-red-50 border-red-100 text-red-800' :
                        check.severity === 'warning' ? 'bg-orange-50 border-orange-100 text-orange-800' :
                        'bg-blue-50 border-blue-100 text-blue-800'
                    }`}>
                        {check.severity === 'error' && <AlertTriangle className="w-5 h-5 shrink-0" />}
                        {check.severity === 'warning' && <AlertTriangle className="w-5 h-5 shrink-0" />}
                        {check.severity === 'info' && <Info className="w-5 h-5 shrink-0" />}

                        <div className="text-sm">
                            <p className="font-semibold mb-0.5">{check.isConsistent ? 'Info' : 'Attenzione'}</p>
                            <p>{check.message}</p>
                        </div>
                    </div>
                )
            })}
        </div>
    </div>
  );
};

export default ConsistencyChecks;

import React, { useState } from 'react';
import Header from './components/Header';
import FileUpload from './components/FileUpload';
import GeneralInfoCard from './components/GeneralInfoCard';
import SummaryCard from './components/SummaryCard';
import LineItemsSection from './components/LineItemsSection';
import SimpleExplanation from './components/SimpleExplanation';
import ConsistencyChecks from './components/ConsistencyChecks';
import { extractTextFromPdf } from './services/pdfService';
import { analyzePayslipWithGemini } from './services/geminiService';
import { AnalysisResult, AnalysisStatus } from './types';
import { Loader2, RefreshCw } from 'lucide-react';

const App: React.FC = () => {
  const [status, setStatus] = useState<AnalysisStatus>('idle');
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileSelect = async (file: File) => {
    setStatus('extracting');
    setError(null);
    setResult(null);

    try {
      // 1. Extract Text
      const text = await extractTextFromPdf(file);

      // 2. Analyze with AI
      setStatus('analyzing');
      const analysis = await analyzePayslipWithGemini(text);

      // 3. Show Results
      setResult(analysis);
      setStatus('success');
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Si è verificato un errore imprevisto.");
      setStatus('error');
    }
  };

  const handleReset = () => {
    setStatus('idle');
    setResult(null);
    setError(null);
  };

  return (
    <div className="min-h-screen pb-12">
      <Header />

      <main className="max-w-5xl mx-auto px-4 pt-8">

        {/* State: IDLE or LOADING or ERROR */}
        {!result && (
          <div className="max-w-2xl mx-auto mt-12">
             <FileUpload onFileSelect={handleFileSelect} isLoading={status === 'extracting' || status === 'analyzing'} />

             {status === 'extracting' && (
                <div className="mt-6 text-center text-slate-500 animate-pulse">
                    Lettura del PDF in corso...
                </div>
             )}
             {status === 'analyzing' && (
                <div className="mt-6 text-center text-blue-600 flex flex-col items-center gap-2">
                    <Loader2 className="w-6 h-6 animate-spin" />
                    <span className="font-medium">L'esperto AI sta analizzando la tua busta paga...</span>
                    <span className="text-xs text-slate-400">Potrebbe richiedere fino a 30 secondi</span>
                </div>
             )}

             {status === 'error' && (
                <div className="mt-6 p-4 bg-red-50 border border-red-100 rounded-lg text-red-700 text-center">
                    <p className="font-bold">Errore</p>
                    <p>{error}</p>
