import * as pdfjsLib from 'pdfjs-dist';

// Define the worker source URL.
// We explicitly point to version 4.10.38 to match the import map in index.html.
// Using the specific 'min.js' build ensures compatibility with standard browser loading.
pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://unpkg.com/pdfjs-dist@4.10.38/build/pdf.worker.min.js';

export const extractTextFromPdf = async (file: File): Promise<string> => {
  try {
    const arrayBuffer = await file.arrayBuffer();

    // In some ESM environments, getDocument might need to be accessed directly or via default.
    // pdfjsLib imported via * as usually captures named exports.
    const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
    const pdfDocument = await loadingTask.promise;

    let fullText = '';
    const numPages = pdfDocument.numPages;

    for (let pageNum = 1; pageNum <= numPages; pageNum++) {
      const page = await pdfDocument.getPage(pageNum);
      const textContent = await page.getTextContent();

      // Extract text items and join them with spaces/newlines to approximate layout
      const pageText = textContent.items
        .map((item: any) => item.str)
        .join(' ');

      fullText += `--- Pagina ${pageNum} ---\n${pageText}\n\n`;
    }

    if (fullText.trim().length < 50) {
        throw new Error("Il PDF sembra vuoto o è un'immagine scansionata (OCR non supportato). Carica un PDF digitale.");
    }

    return fullText;
  } catch (error: any) {
    console.error("Errore estrazione PDF:", error);

    // Generic user-friendly error messages based on common PDF.js failures
    if (error.name === 'MissingPDFException') {
        throw new Error("Il file PDF risulta mancante o corrotto.");
    }
    if (error.name === 'InvalidPDFException') {
        throw new Error("File non valido. Assicurati che sia un PDF corretto.");
    }
    if (error.message && error.message.includes("fake worker")) {
         throw new Error("Errore tecnico nel caricamento del motore PDF. Riprova a ricaricare la pagina.");
    }

    throw new Error("Impossibile leggere il PDF. Assicurati che sia un documento digitale valido (non una scansione) e non protetto da password.");
  }
};

