import React, { useState } from 'react';
import Header from './components/Header';
import FileUpload from './components/FileUpload';
import GeneralInfoCard from './components/GeneralInfoCard';
import SummaryCard from './components/SummaryCard';
import LeaveStatusCard from './components/LeaveStatusCard';
import LineItemsSection from './components/LineItemsSection';
import SimpleExplanation from './components/SimpleExplanation';
import ConsistencyChecks from './components/ConsistencyChecks';
import { extractTextFromPdf } from './services/pdfService';
import { analyzePayslipWithGemini } from './services/geminiService';
import { generateAnalysisPdf } from './services/pdfExportService';
import { AnalysisResult, AnalysisStatus } from './types';
import { Loader2, RefreshCw, Download } from 'lucide-react';

const App: React.FC = () => {
  const [status, setStatus] = useState<AnalysisStatus>('idle');
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileSelect = async (file: File) => {
    setStatus('extracting');
    setError(null);
    setResult(null);

    try {
      // 1. Extract Text
      const text = await extractTextFromPdf(file);

      // 2. Analyze with AI
      setStatus('analyzing');
      const analysis = await analyzePayslipWithGemini(text);

      // 3. Show Results
      setResult(analysis);
      setStatus('success');
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Si è verificato un errore imprevisto.");
      setStatus('error');
    }
  };

  const handleReset = () => {
    setStatus('idle');
    setResult(null);
    setError(null);
  };

  const handleDownloadPdf = () => {
    if (result) {
      generateAnalysisPdf(result);
    }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans text-slate-900">
      <Header />

      <main className="flex-1 max-w-5xl w-full mx-auto px-4 py-8">

        {/* State: Idle or Loading */}
        {(status === 'idle' || status === 'extracting' || status === 'analyzing') && (
          <div className="max-w-xl mx-auto mt-12">
            <FileUpload 
              onFileSelect={handleFileSelect} 
              isLoading={status === 'extracting' || status === 'analyzing'} 
            />

            {(status === 'extracting' || status === 'analyzing') && (
              <div className="mt-8 text-center space-y-3">
                <div className="flex justify-center">
                  <Loader2 className="w-10 h-10 text-blue-600 animate-spin" />
                </div>
                <h3 className="text-xl font-semibold text-slate-800">
                  {status === 'extracting' ? 'Lettura PDF in corso...' : 'L\'Intelligenza Artificiale sta analizzando...'}
                </h3>
                <p className="text-slate-500 max-w-sm mx-auto">
                  {status === 'extracting' 
                    ? 'Stiamo estraendo il testo dalla tua busta paga digitale.' 
                    : 'Stiamo controllando calcoli, ferie, permessi e cercando eventuali anomalie.'}
                </p>
              </div>
            )}
          </div>
        )}

        {/* State: Error */}
        {status === 'error' && (
          <div className="max-w-xl mx-auto mt-12 text-center">
            <div className="bg-red-50 border border-red-200 rounded-xl p-8">
              <h3 className="text-xl font-bold text-red-800 mb-2">Ops! Qualcosa è andato storto</h3>
              <p className="text-red-600 mb-6">{error}</p>
              <button 
                onClick={handleReset}
                className="inline-flex items-center gap-2 px-6 py-3 bg-white border border-red-200 text-red-700 font-semibold rounded-lg hover:bg-red-50 transition-colors shadow-sm"
              >
                <RefreshCw className="w-4 h-4" />
                Riprova
              </button>
            </div>
          </div>
        )}

        {/* State: Success (Results) */}
        {status === 'success' && result && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">

            {/* Toolbar */}
            <div className="flex justify-between items-center mb-4">
              <button 
                onClick={handleReset}
                className="text-sm text-slate-500 hover:text-slate-800 flex items-center gap-1"
              >
                <RefreshCw className="w-4 h-4" />
                Analizza un'altra busta
              </button>

              <button 
                onClick={handleDownloadPdf}
                className="inline-flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white font-medium rounded-lg shadow-sm transition-colors"
              >
                <Download className="w-4 h-4" />
                Scarica Report PDF
              </button>
            </div>

            <SummaryCard result={result} />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <div className="lg:col-span-2 space-y-6">
                <LeaveStatusCard data={result.leaveAnalysis} />
                <SimpleExplanation data={result.simpleExplanation} />
                <LineItemsSection items={result.lineItems} />
              </div>

              <div className="lg:col-span-1 space-y-6">
                <GeneralInfoCard data={result.generalData} />
                <ConsistencyChecks checks={result.consistencyChecks} />
              </div>
            </div>

          </div>
        )}
      </main>

      <footer className="bg-white border-t border-slate-200 mt-12 py-8 text-center text-slate-400 text-sm">
        <p>&copy; {new Date().getFullYear()} Busta Paga Expert. Analisi basata su AI - Verifica sempre con un professionista.</p>
      </footer>
    </div>
  );
};

export default App;

import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { AnalysisResult } from "../types";
import { APP_NAME } from "../constants";

export const generateAnalysisPdf = (data: AnalysisResult) => {
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.width;
  const margin = 14;
  let finalY = 0;

  // --- Colori ---
  const primaryColor = [37, 99, 235]; // Blue-600
  const secondaryColor = [71, 85, 105]; // Slate-600
  const lightBg = [248, 250, 252]; // Slate-50

  // --- Header ---
  doc.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
  doc.rect(0, 0, pageWidth, 20, 'F');

  doc.setTextColor(255, 255, 255);
  doc.setFontSize(16);
  doc.setFont("helvetica", "bold");
  doc.text(APP_NAME, margin, 13);

  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  const dateStr = new Date().toLocaleDateString('it-IT', { day: 'numeric', month: 'long', year: 'numeric' });
  doc.text(`Report generato il ${dateStr}`, pageWidth - margin, 13, { align: 'right' });

  // --- Riepilogo Finanziario (Box in alto) ---
  doc.setTextColor(0, 0, 0);
  const summaryTop = 30;

  // Box Netto
  doc.setFillColor(220, 252, 231); // Green-100
  doc.setDrawColor(22, 163, 74); // Green-600
  doc.roundedRect(margin, summaryTop, 60, 25, 2, 2, 'FD');

  doc.setFontSize(10);
  doc.setTextColor(21, 128, 61); // Green-700
  doc.text("NETTO IN BUSTA", margin + 5, summaryTop + 8);
  doc.setFontSize(16);
  doc.setFont("helvetica", "bold");
  doc.text(data.finalSummary.netTotal, margin + 5, summaryTop + 18);

  // Box Lordo
  doc.setFillColor(239, 246, 255); // Blue-50
  doc.setDrawColor(37, 99, 235); // Blue-600
  doc.roundedRect(margin + 65, summaryTop, 55, 25, 2, 2, 'FD');

  doc.setFontSize(10);
  doc.setTextColor(30, 64, 175); // Blue-800
  doc.setFont("helvetica", "normal");
  doc.text("LORDO TOTALE", margin + 70, summaryTop + 8);
  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.text(data.finalSummary.grossTotal, margin + 70, summaryTop + 18);

  // Box Trattenute
  doc.setFillColor(254, 242, 242); // Red-50
  doc.setDrawColor(220, 38, 38); // Red-600
  doc.roundedRect(margin + 125, summaryTop, 55, 25, 2, 2, 'FD');

  doc.setFontSize(10);
  doc.setTextColor(153, 27, 27); // Red-800
  doc.setFont("helvetica", "normal");
  doc.text(`TRATTENUTE (${data.calculations.deductionPercentage})`, margin + 130, summaryTop + 8);
  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.text(data.calculations.totalDeductions, margin + 130, summaryTop + 18);

  finalY = summaryTop + 35;

  // --- Dati Generali (Tabella) ---
  doc.setFontSize(12);
  doc.setTextColor(secondaryColor[0], secondaryColor[1], secondaryColor[2]);
  doc.setFont("helvetica", "bold");
  doc.text("Dati Generali", margin, finalY);

  const generalDataBody = [
    ["Azienda", data.generalData.employer, "Contratto", data.generalData.contractType],
    ["Dipendente", data.generalData.employee, "CCNL", data.generalData.ccnl],
    ["Periodo", data.generalData.payPeriod, "Livello", data.generalData.level],
  ];

  autoTable(doc, {
    startY: finalY + 3,
    head: [],
    body: generalDataBody,
    theme: 'plain',
    styles: { fontSize: 9, cellPadding: 1.5 },
    columnStyles: {
      0: { fontStyle: 'bold', textColor: secondaryColor, cellWidth: 25 },
      1: { cellWidth: 65 },
      2: { fontStyle: 'bold', textColor: secondaryColor, cellWidth: 25 },
      3: { cellWidth: 'auto' }
    },
  });

  finalY = (doc as any).lastAutoTable.finalY + 10;

  // --- Ferie & ROL Analysis ---
  doc.setFontSize(12);
  doc.setTextColor(secondaryColor[0], secondaryColor[1], secondaryColor[2]);
  doc.setFont("helvetica", "bold");
  doc.text("Ferie & Permessi", margin, finalY);

  const leaveBody = [
    [
      "FERIE", 
      data.leaveAnalysis.vacation.unit,
      data.leaveAnalysis.vacation.previousBalance, 
      data.leaveAnalysis.vacation.accrued, 
      data.leaveAnalysis.vacation.taken, 
      data.leaveAnalysis.vacation.balance
    ],
    [
      "R.O.L. / EX-FEST", 
      data.leaveAnalysis.rol.unit,
      data.leaveAnalysis.rol.previousBalance, 
      data.leaveAnalysis.rol.accrued, 
      data.leaveAnalysis.rol.taken, 
      data.leaveAnalysis.rol.balance
    ]
  ];

  autoTable(doc, {
    startY: finalY + 3,
    head: [['Tipologia', 'Unità', 'Residuo Prec.', 'Maturato', 'Goduto', 'Saldo Finale']],
    body: leaveBody,
    theme: 'striped',
    headStyles: { fillColor: secondaryColor, textColor: 255, fontStyle: 'bold' },
    styles: { fontSize: 9, cellPadding: 2, halign: 'center' },
    columnStyles: {
      0: { halign: 'left', fontStyle: 'bold' }
    }
  });

  finalY = (doc as any).lastAutoTable.finalY + 5;

  // Nota dell'esperto (Ferie)
  if (data.leaveAnalysis.humanExplanation) {
      doc.setFontSize(9);
      doc.setFont("helvetica", "italic");
      doc.setTextColor(100);
      const splitNote = doc.splitTextToSize(`Nota: ${data.leaveAnalysis.humanExplanation}`, pageWidth - (margin * 2));
      doc.text(splitNote, margin, finalY + 3);
      finalY += (splitNote.length * 4) + 8;
  } else {
      finalY += 5;
  }

  // --- Spiegazione Semplice ---
  doc.setFontSize(12);
  doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
  doc.setFont("helvetica", "bold");
  doc.text("In parole semplici", margin, finalY);

  doc.setFontSize(10);
  doc.setTextColor(0, 0, 0);
  doc.setFont("helvetica", "normal");

  const splitSummary = doc.splitTextToSize(data.simpleExplanation.summary, pageWidth - (margin * 2));
  doc.text(splitSummary, margin, finalY + 6);

  const summaryHeight = splitSummary.length * 4;
  finalY += 10 + summaryHeight;

  // Punti chiave
  data.simpleExplanation.keyTakeaways.forEach((point) => {
      // Check page break
      if (finalY > 270) {
        doc.addPage();
        finalY = 20;
      }
      doc.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
      doc.circle(margin + 2, finalY - 1, 1, 'F');
      const splitPoint = doc.splitTextToSize(point, pageWidth - (margin * 2) - 5);
      doc.text(splitPoint, margin + 5, finalY);
      finalY += (splitPoint.length * 4) + 2;
  });

  finalY += 8;

  // --- Tabella Dettaglio Voci ---
  if (finalY > 240) {
      doc.addPage();
      finalY = 20;
  }

  doc.setFontSize(12);
  doc.setTextColor(secondaryColor[0], secondaryColor[1], secondaryColor[2]);
  doc.setFont("helvetica", "bold");
  doc.text("Dettaglio Voci", margin, finalY);

  const tableBody = data.lineItems.map(item => [
    item.name,
    item.category,
    item.amount,
    `Cos'è: ${item.explanation.whatIsIt}\nChi paga: ${item.explanation.whoPays}\nNote: ${item.explanation.notes}`
  ]);

  autoTable(doc, {
    startY: finalY + 3,
    head: [['Voce', 'Categoria', 'Importo', 'Dettagli']],
    body: tableBody,
    theme: 'grid',
    headStyles: { fillColor: primaryColor, textColor: 255, fontStyle: 'bold' },
    styles: { fontSize: 9, cellPadding: 3, valign: 'top' },
    columnStyles: {
      0: { cellWidth: 40, fontStyle: 'bold' },
      1: { cellWidth: 30, fontSize: 8, fontStyle: 'italic' },
      2: { cellWidth: 25, halign: 'right', fontStyle: 'bold' },
      3: { cellWidth: 'auto' } // Colonna dettagli flessibile
    },
    didParseCell: function(data) {
        // Color coding for categories based on text logic (optional visual aid)
        if (data.section === 'body' && data.column.index === 1) {
            const cat = data.cell.raw as string;
            if (cat.toLowerCase().includes('trattenute') || cat.toLowerCase().includes('imposte')) {
                data.cell.styles.textColor = [220, 38, 38];
            } else if (cat.toLowerCase().includes('retribuzione')) {
                data.cell.styles.textColor = [22, 163, 74];
            }
        }
    }
  });

  finalY = (doc as any).lastAutoTable.finalY + 10;

  // --- Verifiche & Consigli (Se c'è spazio, altrimenti nuova pagina) ---
  if (finalY > 250) {
      doc.addPage();
      finalY = 20;
  }

  // Consigli di miglioramento
  doc.setFillColor(255, 251, 235); // Amber-50
  doc.setDrawColor(251, 191, 36); // Amber-400
  doc.rect(margin, finalY, pageWidth - (margin * 2), 25, 'FD');

  doc.setFontSize(10);
  doc.setTextColor(180, 83, 9); // Amber-700
  doc.setFont("helvetica", "bold");
  doc.text("Consigli per migliorare lo stipendio:", margin + 5, finalY + 8);
  doc.setFont("helvetica", "normal");
  const tips = doc.splitTextToSize(data.finalSummary.improvementTips, pageWidth - (margin * 2) - 10);
  doc.text(tips, margin + 5, finalY + 16);

  // Footer (pagina corrente)
  const fileName = `Analisi_Busta_Paga_${data.generalData.payPeriod.replace(/\s/g, '_')}.pdf`;
  doc.save(fileName);
};

