              <div className="text-center mb-6">
                <p className="text-sm text-slate-500 font-medium uppercase tracking-wider mb-1">Contributo richiesto</p>
                <p className="text-4xl font-bold text-slate-900">1,00 €</p>
                <p className="text-xs text-slate-400 mt-1">Una tantum / Sessione</p>
              </div>

              <div className="w-full relative z-0 min-h-[150px] flex flex-col justify-center">
                <PayPalScriptProvider options={paypalOptions}>
                  <PayPalButtons
                    style={{ layout: "vertical", shape: "rect", height: 48 }}
                    createOrder={(data, actions) => {
                      return actions.order.create({
                        intent: "CAPTURE",
                        purchase_units: [
                          {
                            amount: {
                              value: "1.00",
                              currency_code: "EUR"
                            },
                            description: "Donazione Busta Paga Expert"
                          },
                        ],
                        application_context: {
                            shipping_preference: "NO_SHIPPING"
                        }
                      });
                    }}
                    onApprove={async (data, actions) => {
                      try {
                        if (actions.order) {
                            await actions.order.capture();
                            onDonationSuccess();
                        }
                      } catch (err) {
                        console.error("Capture Error:", err);
                        alert("Errore nella conferma del pagamento. Riprova.");
                      }
                    }}
                    onError={(err) => {
                        console.error("PayPal Button Error:", err);
                        // Gestione silenziosa degli errori di inizializzazione che non bloccano l'utente
                        // Spesso l'errore "window host" è un falso positivo in ambienti di sviluppo
                    }}
                  />
                </PayPalScriptProvider>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-slate-50 px-8 py-4 border-t border-slate-100 text-center">
            <p className="text-xs text-slate-400">
                Pagamenti processati in sicurezza da PayPal. Destinatario: danieleditu@gmail.com
            </p>
        </div>
      </div>
    </div>
  );
};

export default DonationWall;

import React, { useState } from 'react';
import Header from './components/Header';
import FileUpload from './components/FileUpload';
import GeneralInfoCard from './components/GeneralInfoCard';
import SummaryCard from './components/SummaryCard';
import LeaveStatusCard from './components/LeaveStatusCard';
import LineItemsSection from './components/LineItemsSection';
import SimpleExplanation from './components/SimpleExplanation';
import ConsistencyChecks from './components/ConsistencyChecks';
import DonationWall from './components/DonationWall';
import AdminLoginModal from './components/AdminLoginModal';
import { extractTextFromPdf } from './services/pdfService';
import { analyzePayslipWithGemini } from './services/geminiService';
import { generateAnalysisPdf } from './services/pdfExportService';
import { AnalysisResult, AnalysisStatus } from './types';
import { Loader2, RefreshCw, Download, LockKeyhole } from 'lucide-react';

const ADMIN_EMAIL = "danieleditu@gmail.com";

const App: React.FC = () => {
  const [status, setStatus] = useState<AnalysisStatus>('idle');
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  // State per Paywall e Admin
  const [accessGranted, setAccessGranted] = useState<boolean>(false);
  const [isAdmin, setIsAdmin] = useState<boolean>(false);
  const [showAdminLogin, setShowAdminLogin] = useState<boolean>(false);

  const handleFileSelect = async (file: File) => {
    // Doppio controllo di sicurezza (lato client)
    if (!accessGranted && !isAdmin) return;

    setStatus('extracting');
    setError(null);
    setResult(null);

    try {
      // 1. Extract Text
      const text = await extractTextFromPdf(file);

      // 2. Analyze with AI
      setStatus('analyzing');
      const analysis = await analyzePayslipWithGemini(text);

      // 3. Show Results
      setResult(analysis);
      setStatus('success');
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Si è verificato un errore imprevisto.");
      setStatus('error');
    }
  };

  const handleReset = () => {
    setStatus('idle');
    setResult(null);
    setError(null);
  };

  const handleDownloadPdf = () => {
    if (result) {
      generateAnalysisPdf(result);
    }
  };

  const handleDonationSuccess = () => {
    setAccessGranted(true);
  };

  const handleAdminSubmit = (email: string) => {
    if (email && email.trim().toLowerCase() === ADMIN_EMAIL.toLowerCase()) {
        setIsAdmin(true);
        setAccessGranted(true);
        setShowAdminLogin(false);
    } else {
        alert("Email non autorizzata.");
    }
  };

  const showUpload = accessGranted || isAdmin;

  return (
    // FIX: added bg-slate-50 to ensure background color persists on scroll
    <div className="min-h-screen flex flex-col font-sans text-slate-900 bg-slate-50">
      <Header />

      <main className="flex-1 max-w-5xl w-full mx-auto px-4 py-8 pb-20">

        {/* PAYWALL CHECK */}
        {!showUpload ? (
           <DonationWall onDonationSuccess={handleDonationSuccess} />
        ) : (
            <>
                {/* State: Idle or Loading */}
                {(status === 'idle' || status === 'extracting' || status === 'analyzing') && (
                <div className="max-w-xl mx-auto mt-12 animate-in fade-in zoom-in duration-300">
                    <FileUpload 
                    onFileSelect={handleFileSelect} 
                    isLoading={status === 'extracting' || status === 'analyzing'} 
                    />

                    {(status === 'extracting' || status === 'analyzing') && (
                    <div className="mt-8 text-center space-y-3">
                        <div className="flex justify-center">
                        <Loader2 className="w-10 h-10 text-blue-600 animate-spin" />
                        </div>
                        <h3 className="text-xl font-semibold text-slate-800">
                        {status === 'extracting' ? 'Lettura PDF in corso...' : 'sto analizzando...'}
                        </h3>
                        <p className="text-slate-500 max-w-sm mx-auto">
                        {status === 'extracting' 
                            ? 'Stiamo estraendo il testo dalla tua busta paga digitale.' 
                            : 'Stiamo controllando calcoli, ferie, permessi e cercando eventuali anomalie.'}
                        </p>
                    </div>
                    )}
                </div>
                )}

                {/* State: Error */}
                {status === 'error' && (
                <div className="max-w-xl mx-auto mt-12 text-center">
                    <div className="bg-red-50 border border-red-200 rounded-xl p-8">
                    <h3 className="text-xl font-bold text-red-800 mb-2">Ops! Qualcosa è andato storto</h3>
                    <p className="text-red-600 mb-6">{error}</p>
                    <button 
                        onClick={handleReset}
                        className="inline-flex items-center gap-2 px-6 py-3 bg-white border border-red-200 text-red-700 font-semibold rounded-lg hover:bg-red-50 transition-colors shadow-sm"
                    >
                        <RefreshCw className="w-4 h-4" />
                        Riprova
                    </button>
                    </div>
                </div>
                )}

                {/* State: Success (Results) */}
                {status === 'success' && result && (
                <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">

                    {/* Toolbar */}
                    <div className="flex justify-between items-center mb-4">
                    <button 
                        onClick={handleReset}
                        className="text-sm text-slate-500 hover:text-slate-800 flex items-center gap-1"
                    >
                        <RefreshCw className="w-4 h-4" />
                        Analizza un'altra busta
                    </button>

                    <button 
                        onClick={handleDownloadPdf}
                        className="inline-flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white font-medium rounded-lg shadow-sm transition-colors"
                    >
                        <Download className="w-4 h-4" />
                        Scarica Report PDF
                    </button>
                    </div>

                    <SummaryCard result={result} />

                    {/* FIX: added items-start and min-w-0 to prevent grid overlaps */}
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 items-start">
                        <div className="lg:col-span-2 space-y-6 min-w-0">
                            <LeaveStatusCard data={result.leaveAnalysis} />
                            <SimpleExplanation data={result.simpleExplanation} />
                            <LineItemsSection items={result.lineItems} />
                        </div>

                        <div className="lg:col-span-1 space-y-6 min-w-0">
                            <GeneralInfoCard data={result.generalData} />
                            <ConsistencyChecks checks={result.consistencyChecks} />
                        </div>
                    </div>

                </div>
                )}
            </>
        )}
      </main>

      <footer className="bg-white border-t border-slate-200 mt-12 py-8 text-center text-slate-400 text-sm relative">
        <p>&copy; {new Date().getFullYear()} Busta Paga Expert. Analisi basata su AI - Verifica sempre con un professionista.</p>

        {/* Hidden Admin Trigger */}
        <button 
            onClick={() => setShowAdminLogin(true)}
            className="absolute bottom-4 right-4 text-slate-200 hover:text-slate-400 transition-colors"
            title="Admin Access"
        >
            <LockKeyhole className="w-4 h-4" />
        </button>
      </footer>

      {/* Admin Modal */}
      <AdminLoginModal 
        isOpen={showAdminLogin} 
        onClose={() => setShowAdminLogin(false)} 
        onSubmit={handleAdminSubmit} 
      />
    </div>
  );
};

export default App;
